            <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center text-white font-bold text-xl shadow-lg group-hover:shadow-blue-500/50 transition-all">
              E
            </div>
            <span className="font-bold text-xl tracking-tight text-white">
              Edward<span className="text-blue-500">Kindo</span>
            </span>
          </div>

          {/* Desktop Menu */}
          <div className="hidden md:block">
            <div className="ml-10 flex items-baseline space-x-8">
              {navLinks.map((link) => (
                <a
                  key={link.name}
                  href={link.href}
                  className="relative text-slate-300 hover:text-white px-3 py-2 text-sm font-medium transition-colors duration-200 group"
                >
