import React, { useState, useEffect } from 'react';
import { Menu, X, Plus } from 'lucide-react';

interface NavbarProps {
  onNavigate?: (page: string) => void;
}

export const Navbar: React.FC<NavbarProps> = ({ onNavigate }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: 'Home', href: '#', id: 'home' },
    { name: 'Work', href: '#work', id: 'work' },
    { name: 'Services', href: '#services', id: 'services' },
    { name: 'Contact', href: '#contact', id: 'contact' },
  ];

  const handleLinkClick = (e: React.MouseEvent<HTMLAnchorElement>, linkId: string, href: string) => {
    if (onNavigate && linkId === 'home') {
       e.preventDefault();
       onNavigate('home');
       setIsOpen(false);
    }
    // For other links, if we are on the gallery page, we might want to go home then scroll. 
    // For now, default anchor behavior works if we are on home. 
    // If we are on Gallery, clicking #work won't work unless we go back.
    if (onNavigate && linkId !== 'home') {
       // If we are on a separate view, we should probably go home first.
       // However, to keep it simple, we'll let the user click "Back" or "Home"
       if (linkId === 'work' || linkId === 'services' || linkId === 'contact') {
         // Optionally reset view here if you want any nav click to go back to home layout
         onNavigate('home'); 
         // Allow the anchor click to propagate after a small delay to allow render? 
         // React state updates are batched. 
         setTimeout(() => {
             const element = document.querySelector(href);
             if (element) element.scrollIntoView({ behavior: 'smooth' });
         }, 100);
       }
    }
  };

  return (
    <nav
      className={`fixed w-full z-50 transition-all duration-300 ${
        scrolled
          ? 'bg-dark/90 backdrop-blur-sm border-b border-white/10 py-3'
          : 'bg-transparent py-6'
      }`}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between">
          {/* Logo */}
          <div 
             className="flex-shrink-0 flex items-center gap-2 cursor-pointer group"
             onClick={() => onNavigate && onNavigate('home')}
          >
            <div className="relative">
              <div className="w-8 h-8 border border-blue-500 bg-blue-500/10 flex items-center justify-center font-mono text-blue-500 font-bold hover:bg-blue-500 hover:text-white transition-all">
                E
              </div>
              <div className="absolute -top-1 -right-1 w-2 h-2 bg-white rounded-full"></div>
            </div>
            <span className="font-bold text-xl tracking-tight text-white group-hover:tracking-wide transition-all duration-300">
              Edward<span className="font-mono text-blue-500">_Kindo</span>
            </span>
          </div>

          {/* Desktop Menu */}
          <div className="hidden md:block">
            <div className="flex items-center space-x-1">
              {navLinks.map((link, idx) => (
                <a
                  key={link.name}
                  href={link.href}
                  onClick={(e) => handleLinkClick(e, link.id, link.href)}
                  className="relative text-sm font-mono uppercase tracking-wider text-slate-400 hover:text-white px-4 py-2 transition-colors duration-200 group overflow-hidden"
                >
                  <span className="relative z-10">
                    <span className="text-blue-500 mr-1 opacity-0 group-hover:opacity-100 transition-opacity">/</span>
                    {link.name}
                  </span>
                  {/* Brutalist hover effect */}
                  <div className="absolute inset-0 bg-blue-600/10 scale-x-0 group-hover:scale-x-100 origin-left transition-transform duration-300 ease-out"></div>
                </a>
              ))}
            </div>
          </div>

          {/* Connect Button (Desktop) */}
          <div className="hidden md:block">
             <a 
                href="#contact"
                onClick={(e) => handleLinkClick(e, 'contact', '#contact')}
                className="flex items-center gap-2 px-6 py-2 bg-white text-black font-mono text-xs uppercase font-bold hover:bg-blue-500 hover:text-white transition-colors border border-transparent hover:border-blue-400"
             >
                <Plus size={14} />
                Get in touch
             </a>
          </div>

          {/* Mobile menu button */}
          <div className="flex md:hidden">
            <button
              onClick={() => setIsOpen(!isOpen)}
              className="inline-flex items-center justify-center p-2 text-slate-400 hover:text-white focus:outline-none"
            >
              {isOpen ? <X className="block h-8 w-8" /> : <Menu className="block h-8 w-8" />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      <div className={`md:hidden border-b border-white/10 bg-dark ${isOpen ? 'block' : 'hidden'}`}>
        <div className="px-2 pt-2 pb-3 space-y-1 sm:px-3">
          {navLinks.map((link) => (
            <a
              key={link.name}
              href={link.href}
              onClick={(e) => {
                  handleLinkClick(e, link.id, link.href);
                  setIsOpen(false);
              }}
              className="font-mono uppercase text-slate-300 hover:bg-white/5 hover:text-white block px-3 py-4 text-lg border-l-2 border-transparent hover:border-blue-500"
            >
              {link.name}
            </a>
          ))}
        </div>
      </div>
    </nav>
  );
};

